class DataProcessor {
    private static final Logger LOGGER = Logger.getLogger(DataProcessor.class.getName());
    private final Map<String, EntityProcessor> entityProcessors;
    
    public DataProcessor() {
        this.entityProcessors = new HashMap<>();
        registerProcessors();
    }
    
    private void registerProcessors() {
        entityProcessors.put("Customer", new CustomerProcessor());
        entityProcessors.put("Order", new OrderProcessor());
        entityProcessors.put("Product", new ProductProcessor());
        entityProcessors.put("Invoice", new InvoiceProcessor());
    }
    
    public ProcessingResult processImport(Element root, String requestId) throws Exception {
        ProcessingResult result = new ProcessingResult();
        List<String> warnings = new ArrayList<>();
        
        NodeList entityNodes = root.getElementsByTagName("Entity");
        
        for (int i = 0; i < entityNodes.getLength(); i++) {
            Element entityElement = (Element) entityNodes.item(i);
            String entityType = entityElement.getAttribute("type");
            
            EntityProcessor processor = entityProcessors.get(entityType);
            if (processor == null) {
                warnings.add("Unknown entity type: " + entityType);
                continue;
            }
            
            try {
                EntityData entityData = parseEntityData(entityElement);
                processor.process(entityData);
                result.incrementRecordsProcessed();
            } catch (Exception e) {
                LOGGER.log(Level.WARNING, "Error processing entity " + i, e);
                warnings.add("Error processing entity " + i + ": " + e.getMessage());
            }
        }
        
        result.setWarnings(warnings);
        return result;
    }
    
    public ProcessingResult processUpdate(Element root, String requestId) throws Exception {
        ProcessingResult result = new ProcessingResult();
        List<String> warnings = new ArrayList<>();
        
        NodeList updateNodes = root.getElementsByTagName("Update");
        
        for (int i = 0; i < updateNodes.getLength(); i++) {
            Element updateElement = (Element) updateNodes.item(i);
            String entityType = updateElement.getAttribute("type");
            String entityId = updateElement.getAttribute("id");
            
            EntityProcessor processor = entityProcessors.get(entityType);
            if (processor == null) {
                warnings.add("Unknown entity type: " + entityType);
                continue;
            }
            
            try {
                EntityData entityData = parseEntityData(updateElement);
                entityData.setId(entityId);
                processor.update(entityData);
                result.incrementRecordsProcessed();
            } catch (Exception e) {
                LOGGER.log(Level.WARNING, "Error updating entity " + entityId, e);
                warnings.add("Error updating entity " + entityId + ": " + e.getMessage());
            }
        }
        
        result.setWarnings(warnings);
        return result;
    }
    
    public ProcessingResult processDelete(Element root, String requestId) throws Exception {
        ProcessingResult result = new ProcessingResult();
        List<String> warnings = new ArrayList<>();
        
        NodeList deleteNodes = root.getElementsByTagName("Delete");
        
        for (int i = 0; i < deleteNodes.getLength(); i++) {
            Element deleteElement = (Element) deleteNodes.item(i);
            String entityType = deleteElement.getAttribute("type");
            String entityId = deleteElement.getAttribute("id");
            
            EntityProcessor processor = entityProcessors.get(entityType);
            if (processor == null) {
                warnings.add("Unknown entity type: " + entityType);
                continue;
            }
            
            try {
                processor.delete(entityId);
                result.incrementRecordsProcessed();
            } catch (Exception e) {
                LOGGER.log(Level.WARNING, "Error deleting entity " + entityId, e);
                warnings.add("Error deleting entity " + entityId + ": " + e.getMessage());
            }
        }
        
        result.setWarnings(warnings);
        return result;
    }
    
    private EntityData parseEntityData(Element element) {
        EntityData data = new EntityData();
        data.setType(element.getAttribute("type"));
        
        Map<String, Object> attributes = new HashMap<>();
        NodeList children = element.getChildNodes();
        
        for (int i = 0; i < children.getLength(); i++) {
            Node node = children.item(i);
            if (node.getNodeType() == Node.ELEMENT_NODE) {
                Element childElement = (Element) node;
                String name = childElement.getNodeName();
                
                if (hasChildElements(childElement)) {
                    attributes.put(name, parseNestedData(childElement));
                } else {
                    attributes.put(name, childElement.getTextContent());
                }
            }
        }
        
        data.setAttributes(attributes);
        return data;
    }
    
    private boolean hasChildElements(Element element) {
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            if (children.item(i).getNodeType() == Node.ELEMENT_NODE) {
                return true;
            }
        }
        return false;
    }
    
    private Map<String, Object> parseNestedData(Element element) {
        Map<String, Object> nestedData = new HashMap<>();
        NodeList children = element.getChildNodes();
        
        for (int i = 0; i < children.getLength(); i++) {
            Node node = children.item(i);
            if (node.getNodeType() == Node.ELEMENT_NODE) {
                Element childElement = (Element) node;
                String name = childElement.getNodeName();
                
                if (hasChildElements(childElement)) {
                    nestedData.put(name, parseNestedData(childElement));
                } else {
                    nestedData.put(name, childElement.getTextContent());
                }
            }
        }
        
        return nestedData;
    }
}

interface EntityProcessor {
    void process(EntityData data) throws Exception;
    void update(EntityData data) throws Exception;
    void delete(String id) throws Exception;
}

class CustomerProcessor implements EntityProcessor {
    private static final Logger LOGGER = Logger.getLogger(CustomerProcessor.class.getName());
    
    @Override
    public void process(EntityData data) throws Exception {
        validateCustomerData(data);
        LOGGER.info("Processing customer: " + data.getAttributes().get("name"));
    }
    
    @Override
    public void update(EntityData data) throws Exception {
        validateCustomerData(data);
        LOGGER.info("Updating customer: " + data.getId());
    }
    
    @Override
    public void delete(String id) throws Exception {
        LOGGER.info("Deleting customer: " + id);
    }
    
    private void validateCustomerData(EntityData data) throws ValidationException {
        if (!data.getAttributes().containsKey("name")) {
            throw new ValidationException("Customer name is required");
        }
    }
}

